+        msg[pos + 1] = 0x33;
+        pos += 2;
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x26;
+        pos += 2;
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x24;
+        pos += 2;
