+                            .data = complete_data[0..len],
+                            .is_binary = is_binary,
+                            .owned = true,
+                        };
+                    }
+                    continue;
+                },
+                else => {
+                    wasm_allocator.free(payload);
+                    continue;
+                },
+            }
+        }
+    }
+};

